+        fn register(
+            &self,
+            source: &dyn Source,
+            token: Token,
+            _interest: Interest,
+        ) -> io::Result<()> {
+            let fd = source.raw_fd();
+            let mut state = self.state.lock().expect("lock poisoned");
+
+            if state.source_to_token.contains_key(&fd) {
+                return Err(io::Error::new(
+                    io::ErrorKind::AlreadyExists,
+                    "source already registered",
